namespace Components;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@namespace Components

<h3>Shipping Information</h3>

<div class="mb-3">
    <label class="form-label">Name</label>
    <input class="form-control" value="@Shipping.Name"
           @onchange="e => Shipping.Name = e.Value?.ToString() ?? string.Empty" />
</div>

<div class="mb-3">
    <label class="form-label">Address</label>
    <input class="form-control" value="@Shipping.Address"
           @onchange="e => Shipping.Address = e.Value?.ToString() ?? string.Empty" />
</div>

<div class="mb-3">
    <label class="form-label">City</label>
    <input class="form-control" value="@Shipping.City"
           @onchange="e => Shipping.City = e.Value?.ToString() ?? string.Empty" />
</div>

<div class="mb-3">
    <label class="form-label">Zip Code</label>
    <input class="form-control" value="@Shipping.ZipCode"
           @onchange="e => Shipping.ZipCode = e.Value?.ToString() ?? string.Empty" />
</div>

@if (!string.IsNullOrWhiteSpace(validationMessage))
{
    <div class="alert alert-danger">@validationMessage</div>
}

<button class="btn btn-primary" @onclick="HandleNext">Next</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private string? validationMessage;

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await OnNext.InvokeAsync();
    }
}

@namespace Components

<h3>Payment Information</h3>

<div class="mb-3">
    <label class="form-label">Card Number</label>
    <input class="form-control" value="@Payment.CardNumber"
           @onchange="e => Payment.CardNumber = e.Value?.ToString() ?? string.Empty" />
</div>

<div class="mb-3">
    <label class="form-label">Expiry Date</label>
    <input class="form-control" placeholder="MM/YY" value="@Payment.ExpiryDate"
           @onchange="e => Payment.ExpiryDate = e.Value?.ToString() ?? string.Empty" />
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="OnBack.InvokeAsync">Back</button>
    <button class="btn btn-success" @onclick="OnPlaceOrder.InvokeAsync">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback OnPlaceOrder { get; set; }
}

@namespace Components

<div class="checkout-wizard">
    <p class="text-muted">Step @currentStep of 2</p>

    @if (currentStep == 1)
    {
        <ShippingStep Shipping="order.Shipping" OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="order.Payment"
                     OnBack="GoToShipping"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order order = new();
    private int currentStep = 1;

    private void GoToPayment() => currentStep = 2;
    private void GoToShipping() => currentStep = 1;

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}

